import json, pathlib

def load_records(path: str) -> list[dict]:
    return json.loads(pathlib.Path(path).read_text())

def prepare_features(records: list[dict], label_key: str = "label") -> tuple[list, list]:
    """
    Extract feature vectors and labels from raw records.
    - Skip records missing required keys.
    - Normalize numeric fields to floats.
    - Return (features, labels) as parallel lists.
    """
    required = {"text", "score", label_key}

    # Filter records, extract and normalize features
    features = [
        {
            "text": rec["text"].strip().lower(),
            "score": float(rec["score"]),
            "tags": [t.lower() for t in rec.get("tags", [])],
        }
        for rec in records
        if required.issubset(rec.keys()) and rec["score"] is not None
    ]

    labels = [rec[label_key] for rec in records if required.issubset(rec.keys())]

    return features, labels


